// // This module implements a 2-to-1 multiplexer where the output m is the inverse of the input x when s=0, and the inverse of the input y when s=1.
module top_module(
    input x,
    input y,
    input s,
    output reg m
    );always @ (x or y or s)
    begin
        if (s == 0)
            m = x;
        else
            m = y;
    end
endmodule
